module top_module(
  input RST, 
  input CK, 
  input D, 
  output Q, 
  output QN 
);reg q_reg;


  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ ( posedge CK or posedge RST or posedge dbg_halt)
if (RST) begin
  q_reg <= 1'b0;
end else begin
  q_reg <= D;
end

assign Q = q_reg;
assign QN = ~q_reg;endmodule
